// receive reads result from the decoder in a loop and sends down the result channel.
func (sw *StreamWatcher) receive() {
        defer utilruntime.HandleCrash()
        defer close(sw.result)
        defer sw.Stop()
        for {
                action, obj, err := sw.source.Decode()
                if err != nil {
                        switch err {
                        case io.EOF:
