        if err != nil {
                return "", nil, fmt.Errorf("unable to decode watch event: %v", err)
        }
        return watch.EventType(got.Type), obj, nil
}

// Close closes the underlying r.
func (d *Decoder) Close() {
        d.decoder.Close()
