**File:** `client-go--v0.32.0/tools/cache/reflector.go`

```go
// Reflector owns a ListerWatcher and a Store (DeltaFIFO).
// It is the bridge between the watch stream and the queue.
type Reflector struct {
    name            string
    expectedType    reflect.Type
    expectedGVK     *schema.GroupVersionKind
    store           Store          // always a *DeltaFIFO in practice
    listerWatcher   ListerWatcher
    // ...
}

// Run is the top-level entry point, called by controller.Run() in a goroutine.
// Retries ListAndWatch with exponential backoff on error.
func (r *Reflector) Run(stopCh <-chan struct{}) {
    wait.BackoffUntil(func() {
        if err := r.ListAndWatch(stopCh); err != nil {
            r.watchErrorHandler(r, err)
        }
    }, r.backoffManager, true, stopCh)
}

// ListAndWatch: initial sync then continuous watch
func (r *Reflector) ListAndWatch(stopCh <-chan struct{}) error {
    // Path A (WatchList feature gate): r.watchList() — streaming initial list via watch
    // Path B (default):                r.list()      — paginated LIST then watch
    if fallbackToList {
        err = r.list(stopCh)   // calls syncWith() → store.Replace()
    }
    return r.watchWithResync(w, stopCh)
}

// syncWith converts a []runtime.Object from the initial LIST into a
// store.Replace() call, which enqueues Sync/Replaced deltas for all objects.
func (r *Reflector) syncWith(items []runtime.Object, resourceVersion string) error {
    found := make([]interface{}, 0, len(items))
    for _, item := range items { found = append(found, item) }
    return r.store.Replace(found, resourceVersion)  // → DeltaFIFO.Replace()
}

// watchWithResync starts the periodic resync goroutine then calls watch()
func (r *Reflector) watchWithResync(w watch.Interface, stopCh <-chan struct{}) error {
    resyncerrc := make(chan error, 1)
    cancelCh := make(chan struct{})
    defer close(cancelCh)
    go r.startResync(stopCh, cancelCh, resyncerrc)  // periodic store.Resync()
    return r.watch(w, stopCh, resyncerrc)
}

// watch: the steady-state loop. Opens a new watch if w==nil, then calls handleWatch.
func (r *Reflector) watch(w watch.Interface, stopCh <-chan struct{}, resyncerrc chan error) error {
    for {
        if w == nil {
            options := metav1.ListOptions{
                ResourceVersion: r.LastSyncResourceVersion(),
                AllowWatchBookmarks: true,
                TimeoutSeconds: &timeoutSeconds,
            }
            w, err = r.listerWatcher.Watch(options)  // → ListWatch.Watch() → Request.Watch()
        }
        err = handleWatch(start, w, r.store, r.expectedType, r.expectedGVK,
            r.name, r.typeDescription, r.setLastSyncResourceVersion,
            r.clock, resyncerrc, stopCh)
        w.Stop(); w = nil
        // retry / backoff on error
    }
}
```

`handleWatch` and `handleAnyWatch` are package-level functions (not methods):

```go
// handleWatch: thin wrapper, sets exitOnWatchListBookmarkReceived=false
func handleWatch(start time.Time, w watch.Interface, store Store,
    expectedType reflect.Type, expectedGVK *schema.GroupVersionKind,
    name, expectedTypeName string,
    setLastSyncResourceVersion func(string),
    clock clock.Clock, errCh chan error, stopCh <-chan struct{}) error {
    _, err := handleAnyWatch(start, w, store, expectedType, expectedGVK, name,
        expectedTypeName, setLastSyncResourceVersion,
        false /*exitOnWatchListBookmarkReceived*/, clock, errCh, stopCh)
    return err
}

// handleAnyWatch: the core event dispatch loop.
// Reads from w.ResultChan() and calls store.Add/Update/Delete for each event.
func handleAnyWatch(start time.Time, w watch.Interface, store Store, ...) (bool, error) {
    for {
        select {
        case <-stopCh:
            return watchListBookmarkReceived, errorStopRequested
        case err := <-errCh:
            return watchListBookmarkReceived, err
        case event, ok := <-w.ResultChan():   // ← reads from StreamWatcher.result chan
            if !ok { break loop }
            // type-check event.Object against expectedType / expectedGVK ...
            switch event.Type {
            case watch.Added:
                store.Add(event.Object)       // → DeltaFIFO.Add()
            case watch.Modified:
                store.Update(event.Object)    // → DeltaFIFO.Update()
            case watch.Deleted:
                store.Delete(event.Object)    // → DeltaFIFO.Delete()
            case watch.Bookmark:
                // update ResourceVersion only; check for WatchList annotation
            }
            setLastSyncResourceVersion(resourceVersion)
        }
    }
}
```

