### Layer 3 — DeltaFIFO Queue

**File:** `client-go--v0.32.0/tools/cache/delta_fifo.go`

```go
type DeltaFIFO struct {
    lock  sync.RWMutex
    cond  sync.Cond          // signalled on every enqueue; Pop() waits on this
    items map[string]Deltas  // key → accumulated list of Deltas
    queue []string           // FIFO order of keys; no duplicates
    // ...
    knownObjects  KeyListerGetter  // points to the downstream cache.Store (indexer)
    transformer   TransformFunc
}

// DeltaType constants
const (
    Added    DeltaType = "Added"
    Updated  DeltaType = "Updated"
    Deleted  DeltaType = "Deleted"
    Replaced DeltaType = "Replaced"  // relist after watch error
    Sync     DeltaType = "Sync"      // periodic resync
)

type Delta struct {
    Type   DeltaType
    Object interface{}
}
type Deltas []Delta

// Add/Update/Delete all delegate to queueActionLocked
func (f *DeltaFIFO) Add(obj interface{}) error {
    f.lock.Lock(); defer f.lock.Unlock()
    f.populated = true
    return f.queueActionLocked(Added, obj)
}
func (f *DeltaFIFO) Update(obj interface{}) error { /* same, DeltaType=Updated */ }
func (f *DeltaFIFO) Delete(obj interface{}) error {
    // skips if object not in items AND not in knownObjects (already deleted)
    return f.queueActionLocked(Deleted, obj)
}

// queueActionLocked → queueActionInternalLocked
func (f *DeltaFIFO) queueActionLocked(actionType DeltaType, obj interface{}) error {
    return f.queueActionInternalLocked(actionType, actionType, obj)
}

func (f *DeltaFIFO) queueActionInternalLocked(actionType, internalActionType DeltaType, obj interface{}) error {
    id, _ := f.KeyOf(obj)

    // Optional object transformation (e.g., strip managed fields)
    if f.transformer != nil && !isTombstone && internalActionType != Sync {
        obj, err = f.transformer(obj)
    }

    oldDeltas := f.items[id]
    newDeltas := append(oldDeltas, Delta{actionType, obj})
    newDeltas = dedupDeltas(newDeltas)  // collapses consecutive Deleted deltas

    if _, exists := f.items[id]; !exists {
        f.queue = append(f.queue, id)   // new key: add to FIFO order
    }
    f.items[id] = newDeltas
    f.cond.Broadcast()                  // wake any blocked Pop() callers
    return nil
}

// Pop blocks until an item is available, then removes it from the queue
// and calls process(deltas, isInInitialList).
func (f *DeltaFIFO) Pop(process PopProcessFunc) (interface{}, error) {
    f.lock.Lock(); defer f.lock.Unlock()
    for {
        for len(f.queue) == 0 {
            if f.closed { return nil, ErrFIFOClosed }
            f.cond.Wait()               // releases lock; re-acquires on wake
        }
        id := f.queue[0]
        f.queue = f.queue[1:]
        item := f.items[id]
        delete(f.items, id)

        err := process(item, isInInitialList)   // → processDeltas()
        if e, ok := err.(ErrRequeue); ok {
            f.addIfNotPresent(id, item)         // re-enqueue on transient error
        }
        return item, err
    }
}
```

**Key invariant:** `items[key]` accumulates all deltas for an object between `Pop()` calls. A single `Pop()` delivers the complete history since last processing — the consumer sees every intermediate state.

