### Layer 4 — Controller Dispatch Loop

**File:** `client-go--v0.32.0/tools/cache/controller.go`

```go
// controller.Run() wires everything together:
// - creates a Reflector pointing at the DeltaFIFO
// - runs Reflector.Run() in a goroutine
// - runs processLoop() in the current goroutine
func (c *controller) Run(stopCh <-chan struct{}) {
    r := NewReflectorWithOptions(c.config.ListerWatcher, c.config.ObjectType,
        c.config.Queue, ReflectorOptions{...})
    // ...
    wg.StartWithChannel(stopCh, r.Run)          // goroutine: fills DeltaFIFO
    wait.Until(c.processLoop, time.Second, stopCh)  // drains DeltaFIFO
}

// processLoop: tight loop calling Queue.Pop with the configured Process function.
// For sharedIndexInformer, Process = sharedIndexInformer.HandleDeltas.
func (c *controller) processLoop() {
    for {
        obj, err := c.config.Queue.Pop(PopProcessFunc(c.config.Process))
        if err == ErrFIFOClosed { return }
        if c.config.RetryOnError { c.config.Queue.AddIfNotPresent(obj) }
    }
}

// ResourceEventHandler is the interface user code implements
type ResourceEventHandler interface {
    OnAdd(obj interface{}, isInInitialList bool)
    OnUpdate(oldObj, newObj interface{})
    OnDelete(obj interface{})
}

// processDeltas: the default Process function for non-shared informers.
// For sharedIndexInformer, HandleDeltas calls this with s itself as handler.
func processDeltas(handler ResourceEventHandler, clientState Store,
    deltas Deltas, isInInitialList bool) error {
    for _, d := range deltas {   // oldest → newest
        obj := d.Object
        switch d.Type {
        case Sync, Replaced, Added, Updated:
            if old, exists, _ := clientState.Get(obj); exists {
                clientState.Update(obj)
                handler.OnUpdate(old, obj)
            } else {
                clientState.Add(obj)
                handler.OnAdd(obj, isInInitialList)
            }
        case Deleted:
            clientState.Delete(obj)
            handler.OnDelete(obj)
        }
    }
    return nil
}
```

**Critical detail:** `processDeltas` updates `clientState` (the `cache.Store` / indexer) **and** calls the handler **atomically within the same call**. The cache is always updated before the handler fires.

