### Layer 6 — Per-Listener Goroutine Pair (pop + run)

**File:** `client-go--v0.32.0/tools/cache/shared_informer.go`

Each registered `ResourceEventHandler` gets its own `processorListener` with two goroutines and an unbounded ring buffer:

```go
type processorListener struct {
    nextCh chan interface{}          // unbuffered; run() reads from here
    addCh  chan interface{}          // unbuffered; distribute() writes here
    handler ResourceEventHandler    // the user's handler
    pendingNotifications buffer.RingGrowing  // absorbs bursts between pop and run
    // resync tracking fields ...
}

// add: called by distribute(); sends notification into addCh (blocks if pop is busy)
func (p *processorListener) add(notification interface{}) {
    if a, ok := notification.(addNotification); ok && a.isInInitialList {
        p.syncTracker.Start()
    }
    p.addCh <- notification
}

// pop goroutine: shuttles notifications from addCh → pendingNotifications → nextCh.
// Decouples the producer (distribute) from the consumer (run) with a ring buffer.
func (p *processorListener) pop() {
    defer close(p.nextCh)
    var nextCh chan<- interface{}
    var notification interface{}
    for {
        select {
        case nextCh <- notification:
            // sent to run(); advance ring buffer
            notification, ok = p.pendingNotifications.ReadOne()
            if !ok { nextCh = nil }  // nothing pending: disable this case
        case notificationToAdd, ok := <-p.addCh:
            if !ok { return }
            if notification == nil {
                notification = notificationToAdd
                nextCh = p.nextCh    // enable the send case
            } else {
                p.pendingNotifications.WriteOne(notificationToAdd)  // buffer it
            }
        }
    }
}

// run goroutine: reads from nextCh and calls the user's handler.
// Panics in handlers are caught; the offending notification is skipped after 1s.
func (p *processorListener) run() {
    stopCh := make(chan struct{})
    wait.Until(func() {
        for next := range p.nextCh {
            switch notification := next.(type) {
            case updateNotification:
                p.handler.OnUpdate(notification.oldObj, notification.newObj)
            case addNotification:
                p.handler.OnAdd(notification.newObj, notification.isInInitialList)
                if notification.isInInitialList { p.syncTracker.Finished() }
            case deleteNotification:
                p.handler.OnDelete(notification.oldObj)
            }
        }
        close(stopCh)
    }, 1*time.Second, stopCh)
}
```

