**File:** `client-go--v0.32.0/tools/cache/thread_safe_store.go`

```go
type threadSafeMap struct {
    lock  sync.RWMutex
    items map[string]interface{}  // the actual in-memory object store
    index *storeIndex             // secondary indices (e.g., namespace index)
}

func (c *threadSafeMap) Add(key string, obj interface{}) { c.Update(key, obj) }

func (c *threadSafeMap) Update(key string, obj interface{}) {
    c.lock.Lock(); defer c.lock.Unlock()
    oldObject := c.items[key]
    c.items[key] = obj
    c.index.updateIndices(oldObject, obj, key)  // maintains all registered IndexFuncs
}

func (c *threadSafeMap) Delete(key string) {
    c.lock.Lock(); defer c.lock.Unlock()
    if obj, exists := c.items[key]; exists {
        c.index.updateIndices(obj, nil, key)
        delete(c.items, key)
    }
}
```

