### Complete Call Chain Summary (single Added event)

```
API server sends HTTP chunk: {"type":"ADDED","object":{...Pod JSON...}}
  │
  ▼ rest/request.go
  Request.Watch(ctx)
    └─ watchInternal(ctx)
         └─ client.Do(req)  [HTTP GET /api/v1/pods?watch=true]
              └─ newStreamWatcher(resp)
                   ├─ framer.NewFrameReader(resp.Body)
                   ├─ streaming.NewDecoder(frameReader, streamingSerializer)
                   └─ watch.NewStreamWatcher(
                          restclientwatch.NewDecoder(watchEventDecoder, objectDecoder),
                          errorReporter)
                        └─ go sw.receive()   [goroutine spawned]

  ▼ apimachinery/pkg/watch/streamwatcher.go  [in receive() goroutine]
  sw.receive()
    └─ sw.source.Decode()   [blocks on HTTP body read]
         └─ restclientwatch.Decoder.Decode()
              ├─ d.decoder.Decode(nil, &metav1.WatchEvent{})  [deserialize envelope]
              └─ runtime.Decode(d.embeddedDecoder, got.Object.Raw)  [deserialize Pod]
                   returns (watch.Added, *v1.Pod{...}, nil)
    └─ sw.result <- watch.Event{Type: watch.Added, Object: *v1.Pod{...}}

  ▼ tools/cache/reflector.go  [in handleAnyWatch(), reading sw.result]
  handleAnyWatch()
    └─ case event := <-w.ResultChan():
         └─ switch event.Type == watch.Added:
              └─ store.Add(event.Object)   [store = *DeltaFIFO]

  ▼ tools/cache/delta_fifo.go
  DeltaFIFO.Add(obj *v1.Pod)
    └─ queueActionLocked(Added, obj)
         └─ queueActionInternalLocked(Added, Added, obj)
              ├─ transformer(obj)  [optional: strip managed fields etc.]
              ├─ f.items["default/mypod"] = append(oldDeltas, Delta{Added, obj})
              ├─ f.queue = append(f.queue, "default/mypod")
              └─ f.cond.Broadcast()   [wakes blocked Pop()]

  ▼ tools/cache/controller.go  [in processLoop(), blocked in Pop()]
  controller.processLoop()
    └─ c.config.Queue.Pop(PopProcessFunc(c.config.Process))
         └─ DeltaFIFO.Pop(process)
              ├─ f.cond.Wait() returns
              ├─ item = f.items["default/mypod"]  [Deltas{Delta{Added, *v1.Pod}}]
              ├─ delete(f.items, "default/mypod")
              └─ process(item, isInInitialList)
                   └─ sharedIndexInformer.HandleDeltas(item, false)

  ▼ tools/cache/shared_informer.go
  sharedIndexInformer.HandleDeltas(Deltas{Delta{Added, *v1.Pod}}, false)
    └─ processDeltas(s, s.indexer, deltas, false)
         └─ for d := range deltas:  d.Type == Added
              ├─ s.indexer.Get(obj) → not found
              ├─ s.indexer.Add(obj)   [updates threadSafeMap + indices]
              └─ s.OnAdd(obj, false)
                   └─ s.processor.distribute(addNotification{newObj: obj, isInInitialList: false}, false)
                        └─ for each listener: listener.add(notification)
                             └─ listener.addCh <- notification

  ▼ tools/cache/shared_informer.go  [in processorListener.pop() goroutine]
  processorListener.pop()
    └─ case notificationToAdd := <-p.addCh:
         └─ notification = notificationToAdd
            nextCh = p.nextCh   [enable send to run()]
    └─ case p.nextCh <- notification:
         └─ [delivered to run()]

  ▼ tools/cache/shared_informer.go  [in processorListener.run() goroutine]
  processorListener.run()
    └─ for next := range p.nextCh:
         └─ case addNotification:
              └─ p.handler.OnAdd(notification.newObj, notification.isInInitialList)
                   └─ [USER CODE: e.g., workqueue.Add(key)]
```

