  "complete_call_chain_single_added_event": [
    "API server sends HTTP chunk: {\"type\":\"ADDED\",\"object\":{...Pod JSON...}}",
    "rest/request.go: Request.Watch(ctx) → watchInternal(ctx) → client.Do(req) [HTTP GET /api/v1/pods?watch=true]",
    "rest/request.go: newStreamWatcher(resp) → watch.NewStreamWatcher(restclientwatch.NewDecoder(watchEventDecoder, objectDecoder))",
    "apimachinery/watch/streamwatcher.go: go sw.receive() [goroutine spawned at construction]",
    "apimachinery/watch/streamwatcher.go: sw.receive() → sw.source.Decode() [blocks on HTTP body read]",
    "rest/watch/decoder.go: Decoder.Decode() → d.decoder.Decode(nil, &metav1.WatchEvent{}) → runtime.Decode(embeddedDecoder, got.Object.Raw) → returns (watch.Added, *v1.Pod{...}, nil)",
    "apimachinery/watch/streamwatcher.go: sw.result <- watch.Event{Type: watch.Added, Object: *v1.Pod{...}}",
    "tools/cache/reflector.go: handleAnyWatch() → case event := <-w.ResultChan() → switch watch.Added → store.Add(event.Object)",
    "tools/cache/delta_fifo.go: DeltaFIFO.Add(obj) → queueActionLocked(Added, obj) → queueActionInternalLocked() → transformer(obj) [optional] → items[\"default/mypod\"]=Deltas{Delta{Added,obj}} → queue=append(queue,\"default/mypod\") → cond.Broadcast()",
    "tools/cache/controller.go: processLoop() → Queue.Pop(HandleDeltas) → DeltaFIFO.Pop() unblocks from cond.Wait() → process(Deltas{Delta{Added,*v1.Pod}}, false)",
    "tools/cache/shared_informer.go: HandleDeltas(Deltas, false) [holds blockDeltas lock] → processDeltas(s, s.indexer, deltas, false)",
    "tools/cache/controller.go: processDeltas() → s.indexer.Get(obj) [not found] → s.indexer.Add(obj) [updates threadSafeMap + indices] → s.OnAdd(obj, false)",
    "tools/cache/shared_informer.go: OnAdd() → cacheMutationDetector.AddObject(obj) → processor.distribute(addNotification{newObj:obj, isInInitialList:false}, false)",
    "tools/cache/shared_informer.go: distribute() → for each listener: listener.add(notification) → listener.addCh <- notification",
    "tools/cache/shared_informer.go: processorListener.pop() goroutine → case notificationToAdd := <-p.addCh → notification=notificationToAdd; nextCh=p.nextCh → case p.nextCh <- notification",
    "tools/cache/shared_informer.go: processorListener.run() goroutine → for next := range p.nextCh → case addNotification → p.handler.OnAdd(notification.newObj, false) [USER CODE]"
  ],
  "key_design_properties": {
    "ordering": "DeltaFIFO.queue []string is strict FIFO. Pop() processes one key at a time under lock.",
    "delta_accumulation": "Multiple rapid changes to the same key coalesce into one Deltas slice. Consumer sees full history since last Pop().",
    "cache_consistency": "processDeltas updates s.indexer before calling OnAdd/OnUpdate/OnDelete. Cache is always current when handler fires.",
    "fan_out_isolation": "Each ResourceEventHandler has its own processorListener with independent ring buffer. A slow handler cannot block others.",
    "resync_vs_real_update": "OnUpdate with identical ResourceVersion sets isSync=true. distribute() skips non-syncing listeners for sync events.",
    "panic_safety": "processorListener.run() wraps handler calls in wait.Until with 1s recovery. Panicking handlers skip one notification but continue.",
    "backpressure": "processorListener.pendingNotifications is an unbounded RingGrowing. A stalled handler accumulates memory but never blocks the informer pipeline.",
    "watch_reconnect": "Reflector.watch() loop: on any error, w.Stop(); w=nil. Next iteration opens a fresh watch from LastSyncResourceVersion.",
    "initial_list_sync": "syncWith() calls store.Replace() which enqueues Replaced/Sync deltas for all objects. isInInitialList=true until HasSynced().",
    "transformer": "DeltaFIFO.queueActionInternalLocked applies TransformFunc before enqueue (e.g., strip managedFields). Not applied to tombstones or Sync deltas."
  },
  "goroutine_map": {
    "description": "Goroutines active during steady-state watch for one sharedIndexInformer with N registered handlers",
    "goroutines": [
      {
        "name": "Reflector.Run / ListAndWatch",
        "owner": "controller.Run via wg.StartWithChannel",
        "role": "Drives list+watch lifecycle. Calls handleAnyWatch which blocks on w.ResultChan()."
      },
      {
        "name": "StreamWatcher.receive",
        "owner": "watch.NewStreamWatcher constructor",
        "role": "Blocks on HTTP body read (Decoder.Decode). Sends watch.Event to result chan."
      },
      {
        "name": "Reflector.startResync",
        "owner": "watchWithResync",
        "role": "Periodic timer. Calls store.Resync() to enqueue Sync deltas for all known objects."
      },
      {
        "name": "controller.processLoop",
        "owner": "controller.Run via wait.Until",
        "role": "Drains DeltaFIFO. Calls HandleDeltas synchronously."
      },
      {
        "name": "sharedProcessor.run",
        "owner": "sharedIndexInformer.Run via wg.StartWithChannel",
        "role": "Lifecycle manager for listener goroutines. Starts pop+run per listener."
      },
      {
        "name": "processorListener.pop (x N)",
        "owner": "sharedProcessor.run or addListener",
        "role": "One per registered handler. Shuttles notifications through ring buffer."
      },
      {
        "name": "processorListener.run (x N)",
        "owner": "sharedProcessor.run or addListener",
        "role": "One per registered handler. Calls handler.OnAdd/OnUpdate/OnDelete."
      },
      {
        "name": "cacheMutationDetector.Run",
        "owner": "sharedIndexInformer.Run via wg.StartWithChannel",
        "role": "Periodically checks for in-place mutations of cached objects (debug/test aid)."
      }
    ]
  }
